        import org.apache.commons.logging.Log;
        import org.apache.commons.logging.LogFactory;
        import sailpoint.api.SailPointContext;
        import sailpoint.object.Attributes;
        import sailpoint.object.Identity;
        import sailpoint.object.Attributes;
        import sailpoint.object.QueryOptions;
        import sailpoint.object.Filter;

        import java.text.SimpleDateFormat;
        import java.text.FieldPosition;
        import java.text.DateFormat;
        import java.util.Calendar;
        import java.util.Date;
        import java.util.TimeZone;
        import java.lang.Long;

        import sailpoint.api.SailPointFactory;
        import sailpoint.tools.Util;
        import sailpoint.tools.Message;
        import sailpoint.tools.GeneralException;
        import java.util.*;
        import java.util.Date;
        import java.text.*;
        import javax.naming.Context;
        import javax.naming.InitialContext;
        
        private static Log logger = LogFactory.getLog("rule.ascension.golive");
        public static int count = 0;
        
        logger.debug("Start Go Live Rule");

        QueryOptions qo = new QueryOptions();  
        //qo.addFilter(Filter.eq("inactive",true));
        qo.add(Filter.and(Filter.eq("inactive", true), Filter.isnull("leaverDate")));
        qo.setCloneResults(true);
        Iterator it = context.search(Identity.class, qo, "name");

        while(it.hasNext()){
            String identityName = it.next()[0];

            try{
                Identity identity = context.getObjectByName(Identity.class, identityName);

                if(identity == null)
                    continue;

                ++count;

                SimpleDateFormat format = new SimpleDateFormat("yyyyMMdd");

                Date now = new Date();
                String currentDate = format.format(now);
                identity.setAttribute("leaverDate", currentDate);

                context.saveObject(identity);
                context.commitTransaction();

                identity = null;
                if((count % 100) == 0){ 
                    System.out.println(count);
                    context.decache(); 
                }
            }
            catch(Exception e){
                logger.error("Go Live Rule Error: " + e);
            }
        }

        return ("Finished Processing " + count);
